import{c as a,Q as i,j as t,m as p}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"出使卡尔皮小兄弟会大会","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/167-出使卡尔皮小兄弟会大会.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/167-出使卡尔皮小兄弟会大会.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/lower/167-出使卡尔皮小兄弟会大会.md"};function r(c,e,l,s,n,m){return i(),t("div",null,[...e[0]||(e[0]=[p('<h1 id="出使卡尔皮小兄弟会大会" tabindex="-1">出使卡尔皮小兄弟会大会 <a class="header-anchor" href="#出使卡尔皮小兄弟会大会" aria-label="Permalink to &quot;出使卡尔皮小兄弟会大会&quot;">​</a></h1><p>出使卡尔皮小兄弟会大会 在同所有神父谈话前，我与波坦察神父举行了一次专门的会谈，向他 呈递了教座大人的信件，以您的名义极力劝他在这件事上对您的愿望表示 赞成，巧妙地向他暗示，懂得如何拿自己卖不掉也保存不下来的东西送人 是一种智慧。他要是声明他乐于唯教座大人之命是从，教座大人最微末的 指示对他来说都是命令，那么他就会表现出对于支持此事的最热切的愿 望。后来我逐一与其他所有人谈了话，按照教座大人给我的建议，使用了 比我和他们所有人在一起说话时更强烈和更恳切的语句。所有人都指出这 件事执行起来所面临的困难，这样做可能会造成混乱；但他们全都郑重声 明应该让教座大人满意。从他们有些人的措辞来看，我倾向于认为他们会 把这件事委托给他们的理事长，理事长会在三四名神父的陪同下前往托斯 卡纳，在那里讨论和解决此事。如果采取这个办法，伊拉里翁修士相信， 结果肯定会让我们满意。 做了我已向教座大人报告的这一切，以及拿到神父们交给我负责递送 的信件之后，伊拉里翁修士认为我最好马上启程，奋力在周三傍晚前及时 赶回佛罗伦萨，使外务八人委员会能够再写一封信，在他们散会前送到他 们手里，散会的时间定于下个周六或周日。要在信里告诉他们，八人委员会 对于神父们迟迟没有决议十分不满，并以少量郑重的言辞总结说，除非最终 进行这样一种渴望得到的划分，否则任何其他的决议都不会让他们满意。 我今天傍晚抵达摩德纳这里，但发现骑着马这么急促地赶路让我消受 不了，因为我身子颇感不适。我还记得，根据教座大人的命令，我要在这 里停留一两天；所以我认为最好写信给教座大人，把一切情况向您报告， 就像我亲自前来做出答复一样，尤其是这样做会更快，以防万一您决定在</p><p>①原文为拉丁文：&quot;habito prius maturo examine,et super hoc onerando conscientias vestras.&quot;。 中译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>散会前再次给他们写信。 阿尔贝托阁下的事务代理人吉斯蒙多 · 德 · 桑蒂在这件事上帮了大 忙，对此我愿意向教座大人作证；他的言行举止表现出了对教座大人的忠 心耿耿。敬请教座大人多多关照。</p><p>仆尼科洛 · 马基雅维利 \u2028出使卡尔皮小兄弟会大会</p><p>出访弗朗切斯科 · 圭恰迪尼</p><p>法恩扎，1525年6-7月</p><p>1925年5月底，马基雅维利来到罗马，向教皇献上他所写的 《佛罗伦萨史》。同时，他向处于军事困境中的梅迪奇家族的教 皇克莱门特七世提出了建立国民军的设想，这是他第三次提出自 己的军事改革主张，前两次是1506年向索德里尼、1514年向洛伦 佐 · 德 · 梅迪奇。他的建议给克莱门特七世及其顾问亚科波 · 萨 尔维亚蒂、亚科波 · 萨多莱托等人留下了深刻的印象，他们派他 前往罗马涅的法恩扎，试着向1524年开始受命担任罗马涅长官( il Presidente dell &#39; esarcato di Ravenna e della provincia di Romagna) 的 弗朗切斯科 · 圭恰迪尼说明这个想法，罗马涅被视为试行这个计划 的好地方。 但是，圭恰迪尼对此表达了深深的疑虑。在6月18日给他在罗 马的代表所写的信中，圭恰迪尼指出： “我已经从提到的亚科波 · 萨 尔维亚蒂和卡普阿大主教那里知道了有关马基雅维利来此出使的事 情……我要求你以我的名义了解教皇谋划此事的意图，如果他谋划此 事是为了解决目前的危险，我对现在局势的应对感到无能为力。&quot; 这样一来，前往法恩扎对于马基雅维利而言就是一个未达目 的之旅。他于6月10日或11日从罗马出发，而圭恰迪尼在21日报告 了他的到达并同他举行会谈的消息。7月8日，他仍然在等待教皇 的一个迟迟未到的决定，这是圭恰迪尼6月23日寄出的公文信件， 至于教皇及其顾问见信后会作何感想、有何意图，他对此感到忧心 忡忡。7月26日，厌倦了到那时为止的毫无意义的等待，马基雅维 利宁愿返回佛罗伦萨，放弃了任何希望。“请你对教皇陛下说，” 圭恰迪尼在当天给科隆博的信中写到， &quot;马基雅维利有某些要紧的 事必须会佛罗伦萨去亲自处理，他动身来到我们这里已经一个星期 了，他判断再在此地停留已经不重要了，因为他总是前往教皇陛下 命令去的任何地方”。这就等于承认了这个计划的失败。</p><p>①题注依据贝尔泰利编校本题解等材料编译，信件由王永忠依据贝尔泰利编校本译出。 编者注</p><p>政务与外交著作 Legazioni,commissarie,scrittidi governo</p><p>出访弗朗切斯科·圭恰迪尼</p><p>教皇克莱门特七世致弗朗切斯科 ·圭恰迪尼</p><p>钟爱的儿子： 此诚危急之时，世事纷乱，我们相信总有别的出路，需要我们去争 取，尽管缺乏常规的应对之策，我们丝毫不怀疑，枢机主教会议能够以不 寻常之道摆脱困境，如果一切顺利的话，有一条最佳的出路能够将我们带 入辉煌和幸福的门口。我们枢机主教会议决定派遣钟爱的儿子和佛罗伦萨 公民尼科洛 · 马基雅维利出使贵方，我们从各个方面都对此人抱有极大的 信心并对他的德行十分放心，此人干练通达，经验丰富；他会向你呈报非 常丰富的情况汇报，那些内容的的确确都是我们所设想的计划和我们所希 望的目标。因此，你应该非常认真地听取他的汇报并完完全全地给予他信 任；对你而言，要仔细辨析呈报给你的情况，并毫不犹豫地做出决断，向 我们指明能够使我们受益的出路，让我们完完全全地了解你的每一个想 法，确切无误地看到你所遇到的任何困难和拦阻，让我们明白知道你任何 殚思竭虑的事情； 一旦我们解脱出来，并能够看清楚我们所处的各种情 况，我们就能够继续做出合理的决策。如同我们认为的那样，这是一件生 死存亡的大事，事关教会的危急存亡，近则关乎整个意大利的命运，远则 关乎全体基督教会能否平安。然而，目前需要做出重大决断，不仅依靠命 令法规和个人努力，还要众人尽心尽力和彼此关爱。我们为什么此时此刻 对你寄予如此大的信任，乃是因为你在各种考验面前都能力挽狂澜，具有 各种大能大力，而这位尼科洛对各种事情了如指掌，他会将情况用密信向 我们汇报，所有有关你的情况我们都会知晓。你的所有殷勤努力我们都会 纪念，和你同悲同喜。 呈递罗马的礼物，等等；1525年6月6日，在位第二年</p><p>派往威尼斯</p><p>1525年8月</p><p>委任状</p>',17)])])}const h=a(o,[["render",r]]);export{_ as __pageData,h as default};
